import requests
import os

class Tools:
    @staticmethod
    def run(paper_id: str, fields: str = 'title,abstract,authors,venue,year,citationCount,references,citations,openAccessPdf') -> dict:
        """
        Fetch paper details from Semantic Scholar (Ai2).
        paper_id: Semantic Scholar ID, DOI, arXiv ID, or SHA (e.g. 649def34f8be52c8b66281af98ae884c09aef38b)
        fields: comma-separated list of fields to return
        """
        api_key = os.environ.get('AI2_API_KEY')
        if not api_key:
            return {'error': 'AI2_API_KEY not found'}

        url = f'https://api.semanticscholar.org/graph/v1/paper/{paper_id}'
        params = {'fields': fields}
        headers = {'x-api-key': api_key}

        try:
            r = requests.get(url, params=params, headers=headers, timeout=12)
            r.raise_for_status()
            data = r.json()
            if 'openAccessPdf' in data and data['openAccessPdf']:
                data['pdf_url'] = data['openAccessPdf'].get('url')
            if 'paperId' in data:
                data['url'] = f'https://www.semanticscholar.org/paper/{data["paperId"]}'
            return data
        except Exception as e:
            return {'error': str(e)}

import requests
import os

class Tools:
    @staticmethod
    def run(author_id: str, fields: str = 'name,affiliations,hIndex,paperCount,citationCount,papers.title,papers.year,papers.venue,papers.citationCount') -> dict:
        """
        Fetch author details from Semantic Scholar (Ai2).
        author_id: Semantic Scholar Author ID (e.g. 46314682)
        fields: comma-separated list of fields
        """
        api_key = os.environ.get('AI2_API_KEY')
        if not api_key:
            return {'error': 'AI2_API_KEY not found'}

        url = f'https://api.semanticscholar.org/graph/v1/author/{author_id}'
        params = {'fields': fields}
        headers = {'x-api-key': api_key}

        try:
            r = requests.get(url, params=params, headers=headers, timeout=12)
            r.raise_for_status()
            data = r.json()
            if 'papers' in data:
                data['papers'] = sorted(data['papers'], key=lambda x: x.get('year', 0), reverse=True)[:20]
            return data
        except Exception as e:
            return {'error': str(e)}

import requests
import os

class Tools:
    @staticmethod
    def run(paper_id: str, limit: int = 10, fields: str = 'title,abstract,authors,venue,year,citationCount,openAccessPdf') -> dict:
        """
        Get recommended papers for a seed paper from Semantic Scholar (Ai2).
        paper_id: any valid paper identifier
        limit: number of recommendations (default 10)
        """
        api_key = os.environ.get('AI2_API_KEY')
        if not api_key:
            return {'error': 'AI2_API_KEY not found'}

        url = f'https://api.semanticscholar.org/recommendations/v1/papers/forpaper/{paper_id}'
        params = {'limit': limit, 'fields': fields}
        headers = {'x-api-key': api_key}

        try:
            r = requests.get(url, params=params, headers=headers, timeout=12)
            r.raise_for_status()
            data = r.json()
            for p in data.get('recommendedPapers', []):
                if 'openAccessPdf' in p and p['openAccessPdf']:
                    p['pdf_url'] = p['openAccessPdf'].get('url')
                if 'paperId' in p:
                    p['url'] = f'https://www.semanticscholar.org/paper/{p["paperId"]}'
            return data
        except Exception as e:
            return {'error': str(e)}

import requests
import os

class Tools:
    @staticmethod
    def run(query: str, limit: int = 10, min_score_threshold: float = 0.25) -> dict:
        """
        Semantic search on Ai2 Asta MCP corpus.
        query: natural language or keyword search
        limit: max results
        min_score_threshold: minimum relevance score (0-1)
        """
        api_key = os.environ.get('AI2_API_KEY')
        if not api_key:
            return {'error': 'AI2_API_KEY not found'}

        url = 'https://asta-tools.allen.ai/mcp/v1'
        headers = {
            'x-api-key': api_key,
            'Content-Type': 'application/json',
            'Accept': 'application/json'
        }
        payload = {
            'query': query,
            'limit': limit,
            'min_score_threshold': min_score_threshold
        }

        try:
            r = requests.post(url, headers=headers, json=payload, timeout=15)
            r.raise_for_status()
            data = r.json()
            for res in data.get('results', []):
                if 'paperId' in res:
                    res['url'] = f'https://www.semanticscholar.org/paper/{res["paperId"]}'
            return data
        except Exception as e:
            return {'error': str(e)}
